// 1. Get the first item from the input
const item = $input.first().json;

// 2. Access the 'output' array, then the first message [0], then 'content' [0]
const aiResponse = item.output[0].content[0].text;

// 3. Turn that text string into actual data
const parsed = JSON.parse(aiResponse);

// 4. Send it to the next node
return [{ json: parsed }];
